render.css:
.storage-wrapper { display: flex; flex-direction: column; gap: 12px; }
.value-header { display: flex; align-items: baseline; justify-content: space-between; gap: 8px; }
.kpi-value { font-size: 28px; font-weight: 700; color: var(--ct-text-strong); letter-spacing: -0.02em; font-variant-numeric: tabular-nums; }
.value-total { color: var(--ct-text-muted); font-size: 13px; font-weight: 500; }
.storage-bar { display: flex; height: 12px; background: var(--ct-surface-2); border-radius: 6px; overflow: hidden; }
.ruler { display: flex; justify-content: space-between; font-size: 10px; color: var(--ct-text-muted); font-variant-numeric: tabular-nums; }
.storage-legend { display: flex; gap: 16px; flex-wrap: wrap; font-size: 12px; color: var(--ct-text-muted); }
.legend-item { display: flex; align-items: center; gap: 6px; }
.legend-dot { width: 8px; height: 8px; border-radius: 2px; }
